SELECT 
FROM supplier_installations

    AND status != 'deleted'
    AND id = #{id, jdbcType=BIGINT}
    AND supplier_id = #{supplierId, jdbcType=BIGINT}
    AND order_no = #{orderNo, jdbcType=VARCHAR}
    AND product_summary = #{productSummary, jdbcType=VARCHAR}
    AND customer_name = #{customerName, jdbcType=VARCHAR}
    AND customer_address = #{customerAddress, jdbcType=VARCHAR}
    AND installer_name = #{installerName, jdbcType=VARCHAR}
    AND installer_mobile = #{installerMobile, jdbcType=VARCHAR}
    AND appointment_date = #{appointmentDate, jdbcType=DATE}
    AND appointment_time = #{appointmentTime, jdbcType=VARCHAR}
    AND status = #{status, jdbcType=VARCHAR}
    AND photos = #{photos, jdbcType=VARCHAR}
    AND remark = #{remark, jdbcType=VARCHAR}
    AND completed_at = #{completedAt, jdbcType=TIMESTAMP}
